(window.webpackJsonp=window.webpackJsonp||[]).push([[103],{506:function(n,t,v){"use strict";v.r(t);var _=v(2),p=Object(_.a)({},(function(){var n=this,t=n.$createElement,v=n._self._c||t;return v("ContentSlotsDistributor",{attrs:{"slot-key":n.$parent.slotKey}},[v("p"),v("div",{staticClass:"table-of-contents"},[v("ul")]),v("p"),n._v(" "),v("p",[n._v("开源项目的核心是社区，而不仅仅是代码。演讲者提到了合作和沟通的重要性，以及接受失败和改进的态度。他还讨论了技术选择对人们行为的影响，以及团队合作和避免自我中心的关键。最后，他提到了类似GitHub的服务器端克隆将会推出，并给出了处理工作压力和心理问题的建议。")]),n._v(" "),v("p",[n._v("天才程序员的神话\n演讲者介绍自己并提到他们是版本控制极客。\n演讲者询问观众的编程习惯和团队合作情况。\n演讲者讨论名人效应和程序员的英雄崇拜心理。")]),n._v(" "),v("p",[n._v("在软件开发中，与他人合作是成功的关键\n人们往往在一个“洞穴”中工作，导致进展缓慢。\n合作和沟通能力对于团队合作至关重要。\n个人的自我膨胀会妨碍项目的进展。")]),n._v(" "),v("p",[n._v("开源项目的关键要素\n开源项目的核心是社区，比代码更重要。\n与人互动时要友善，学会给予和接受建设性的批评。\n接受失败，从中学习，不断改进。")]),n._v(" "),v("p",[n._v("如何通过失败和学习来提高自己\n快速失败和快速迭代是学习的最佳方式。\n在团队中与比自己更聪明的人一起工作可以提高自己的技能。\n接受他人的影响和建议，展示自己的脆弱性，可以获得更多的尊重和影响力。")]),n._v(" "),v("p",[n._v("版本控制系统的社会问题\n版本控制系统是解决社会问题的一种技术限制。\n技术选择可以对人们的行为产生重大影响。\n默认设置对人们的行为有很大影响，但不能解决核心社会问题。")]),n._v(" "),v("p",[n._v("项目合作的最佳时机\n合作工具的默认行为会影响团队的动态。\n在项目的不同阶段，需要注意合适的合作时机。\n在项目开始时，需要有明确的设计和使命陈述，并有一定的运行代码。")]),n._v(" "),v("p",[n._v("开源项目中的失败案例和学习\n准备好面对批评和做出改变\n开源项目中应该记录失败的尝试和历史\n设计文档最好由2-3人共同撰写，过多人参与会导致混乱")]),n._v(" "),v("p",[n._v("团队合作和避免自我中心的重要性\n在芝加哥的办公室收到了来自团队的很好的反馈。\n团队合作和避免自我中心是成功的关键。\n要注意工具和团队对合作行为的影响。")]),n._v(" "),v("p",[n._v("技术解决社交问题的挑战\n人们对于项目中的参与者数量存在误解。\n在企业环境中，很难控制项目或环境，因此很难实现理想中的情况。\n在企业环境中，如果你是一个小鱼，可以尝试寻找更有经验的人来提升自己。")]),n._v(" "),v("p",[n._v("如何处理工作压力和心理问题\n类似GitHub的服务器端克隆，将会推出。\n参与门槛较低，对于参与来说可能更好。\n如何处理工作压力和心理问题。")])])}),[],!1,null,null,null);t.default=p.exports}}]);